def validate(args, output):
    nums = args[0]
    # rebuild the tree from its level-order wire form
    def deser(a):
        if not a:
            return None
        root = [a[0], None, None]
        q = [root]; i = 1
        while q and i < len(a):
            node = q.pop(0)
            if i < len(a):
                if a[i] is not None:
                    node[1] = [a[i], None, None]; q.append(node[1])
                i += 1
            if i < len(a):
                if a[i] is not None:
                    node[2] = [a[i], None, None]; q.append(node[2])
                i += 1
        return root
    root = deser(output)
    # in-order must equal the input exactly (so it holds the same values, sorted)
    ino = []
    st, node = [], root
    while st or node:
        while node:
            st.append(node); node = node[1]
        node = st.pop(); ino.append(node[0]); node = node[2]
    if ino != list(nums):
        return False
    # BST property: in-order strictly increasing only if input strictly increasing;
    # the input may contain duplicates, so equal-to-input check above already binds
    # the values. Verify the heights are balanced (|hL - hR| <= 1 everywhere).
    def height(n):
        if n is None:
            return 0, True
        hl, bl = height(n[1])
        hr, br = height(n[2])
        ok = bl and br and abs(hl - hr) <= 1
        return max(hl, hr) + 1, ok
    _, balanced = height(root)
    return balanced

