    def sortedArrayToBST(self, nums):
        # Independent build; same lower-middle choice so the canonical tree
        # matches the optimal solution byte for byte.
        def build(arr):
            if not arr:
                return None
            mid = (len(arr) - 1) // 2
            node = TreeNode(arr[mid])
            node.left = build(arr[:mid])
            node.right = build(arr[mid + 1:])
            return node
        return build(list(nums))

